let type = queries.fetchConfigDetails.data['Value Type'];
let value;

if( components.addConfigValueModal.show && components.addConfigValueTabbedContainer.currentTab === "t0") {
  value = components.addConfigValueFormContainerMarketplace.value;
} 
else if(components.addConfigValueModal.show && components.addConfigValueTabbedContainer.currentTab === "t1") {
  value = components.addConfigValueFormNonSingleTextInputValue.value;
} 
else if(components.addConfigValueModal.show && components.addConfigValueTabbedContainer.currentTab === "t2") {
  value = components.addConfigValueFormNonSingle2TextInputValue.value;
} 
else if( components.updateConfigValueModal.show && components.configValueTabbedContainer.currentTabTitle === "updateConfigValue") {
  value = components.updateConfigValueFormTextInputValue.value;
} 
else if(components.updateConfigValueModal.show && components.configValueTabbedContainer.currentTabTitle === "updateConfigValueNonParam1") {
  value = components.updateConfigValueFormNonSingleTextInputValue.value;
} 
else if(components.updateConfigValueModal.show && components.configValueTabbedContainer.currentTabTitle === "updateConfigValueNonParam2") {
  value = components.updateConfigValueFormNonSingle2TextInputValue.value;
}

let keyValue = {};
switch (type) {
    case 'TYPE_STRING':
      keyValue = { "type": 1, "string_value": value };
      break;

    case 'TYPE_INT':
      keyValue = { "type": 2, "integer_value": JSON.parse(value) };
      break;

    case 'TYPE_BOOLEAN':
      keyValue = { "type": 3, "boolean_value": JSON.parse(value.toLowerCase()) };
      break;

    case 'TYPE_FLOAT':
      keyValue = { "type": 4, "float_value_v2": JSON.parse(value) };
      break;

    case 'TYPE_STRING_ARRAY':
      keyValue = { "type": 5, "string_array_value" : {"string_values": JSON.parse(value)} };
      break;

    case 'TYPE_INT_ARRAY':
      keyValue = { "type": 6, "integer_array_value" : {"integer_values": JSON.parse(value)} };
      break;

    case 'TYPE_BOOLEAN_ARRAY':
      keyValue = { "type": 7, "boolean_array_value" : {"boolean_values": JSON.parse(value)} };
      break;

    case 'TYPE_FLOAT_ARRAY':
      keyValue = { "type": 8, "float_array_value_v2" : {"float_values_v2": JSON.parse(value)} };
      break;

    case 'TYPE_JSON':
      keyValue = { "type": 9, "string_value" : value };
      break;

    default:
      break;
}

//configValueTypeForAddConfigValue.setValue(keyValue);
await actions.setPageVariable("configValueTypeForAddConfigValue", keyValue)
